1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - Next Generation", () => {
6	  it("should return empty result for empty input", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell (underpopulation)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
13	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
14	  });
15	  it("should keep a 2x2 block unchanged (still life, each cell has 3 neighbors)", () => {
16	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
17	    const sortCells = (cells: [number, number][]) =>
18	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
19	    expect(sortCells(result)).toEqual(sortCells([[0, 0], [1, 0], [0, 1], [1, 1]]));
20	  });
21	  it("should rotate a vertical blinker into a horizontal blinker", () => {
22	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
23	    const sortCells = (cells: [number, number][]) =>
24	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
25	    expect(sortCells(result)).toEqual(sortCells([[-1, 1], [0, 1], [1, 1]]));
26	  });
27	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
28	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
29	    const sortCells = (cells: [number, number][]) =>
30	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
31	    expect(sortCells(result)).toEqual(sortCells([[0, 0], [1, 0], [0, 1], [1, 1]]));
32	  });
33	  it("should kill a live cell with 4 or more neighbors (overpopulation)", () => {
34	    // Input pattern: ### / .#. / ###  (center has 6 live neighbors -> dies)
35	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]]);
36	    const sortCells = (cells: [number, number][]) =>
37	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
38	    expect(sortCells(result)).toEqual(
39	      sortCells([[1, -1], [0, 0], [1, 0], [2, 0], [0, 2], [1, 2], [2, 2], [1, 3]])
40	    );
41	  });
42	  it.todo("should handle cells at negative coordinates");
43	});
