1	// game-of-life.ts
2	
3	export type Cell = [number, number];
4	
5	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
6	
7	const neighborsOf = ([x, y]: Cell): Cell[] => {
8	  const neighbors: Cell[] = [];
9	  for (let dx = -1; dx <= 1; dx++) {
10	    for (let dy = -1; dy <= 1; dy++) {
11	      if (dx === 0 && dy === 0) continue;
12	      neighbors.push([x + dx, y + dy]);
13	    }
14	  }
15	  return neighbors;
16	};
17	
18	const survivesOrIsBorn = (isAlive: boolean, liveNeighborCount: number): boolean =>
19	  liveNeighborCount === 3 || (isAlive && liveNeighborCount === 2);
20	
21	export function nextGeneration(cells: Cell[]): Cell[] {
22	  const liveSet = new Set(cells.map(cellKey));
23	
24	  const candidates = new Map<string, Cell>();
25	  for (const cell of cells) {
26	    candidates.set(cellKey(cell), cell);
27	    for (const neighbor of neighborsOf(cell)) {
28	      candidates.set(cellKey(neighbor), neighbor);
29	    }
30	  }
31	
32	  const nextCells: Cell[] = [];
33	  for (const cell of candidates.values()) {
34	    const liveNeighborCount = neighborsOf(cell).filter((n) => liveSet.has(cellKey(n))).length;
35	    if (survivesOrIsBorn(liveSet.has(cellKey(cell)), liveNeighborCount)) {
36	      nextCells.push(cell);
37	    }
38	  }
39	
40	  return nextCells;
41	}
